contract TokenVoting {
    address private owner;
    struct Candidate {
        bytes32 name;
        uint256 votes;
    }
    mapping(uint256 => Candidate) private candidates;
    uint256 private candidateCount;
    mapping(address => bool) private voters;
    mapping(address => bool) private voted;

    modifier onlyOwner() {
        require(msg.sender == owner, "Not the owner");
        _;
    }

    constructor() {
        owner = msg.sender;
    }

    function getCandidateCount() public view returns (uint256) {
        return candidateCount;
    }

    function candidateNames(uint256 id) public view returns (bytes32) {
        require(id < candidateCount, "Invalid candidate ID");
        return candidates[id].name;
    }

    function candidateVotes(uint256 id) public view returns (uint256) {
        require(id < candidateCount, "Invalid candidate ID");
        return candidates[id].votes;
    }

    function addCandidate(bytes32 name) public onlyOwner {
        candidates[candidateCount] = Candidate(name, 0);
        candidateCount++;
    }

    function grantVotingRights(address voter) public onlyOwner {
        voters[voter] = true;
    }

    function hasVotingRights(address voter) public view returns (bool) {
        return voters[voter];
    }

    function vote(uint256 candidateId) public {
        require(candidateId > 0, "Invalid candidate ID");
        require(hasVotingRights(msg.sender), "No voting rights");
        require(!voted[msg.sender], "Already voted");
        require(candidates[candidateId].votes != type(uint256).max, "Candidate no longer available");

        voted[msg.sender] = true;
        candidates[candidateId].votes++;
    }
}
